import React, { Component } from 'react';
import MangaInfo from '../../Data/MangaData.json';

class AllMangadl extends Component {
    render() {
        MangaInfo.map((value, key)=>{
        return (
          <div className="manga-info">
            <div className="children-manga">
              <img src={value.MangaImage} alt=" " />
              <a href>Manga 1</a>
            </div>
            <a href>Chapter 1</a>
            <p>1 hour<br />ago</p>    
        </div>
        );
    });
    }
}

export default AllMangadl;
